def classify_status(code):
    if 200 <= code < 300:
        return "ok"
    if 400 <= code < 500:
        return "client_error_no_blind_retry"
    if 500 <= code < 600:
        return "server_error_maybe_retry"
    return "other"
print(classify_status(400), classify_status(503), classify_status(200))

def should_retry(code):
    return code in {408, 429, 500, 502, 503, 504}
print(should_retry(400), should_retry(503))

class ApiError(Exception):
    def __init__(self, code, msg):
        self.code = code
        super().__init__(msg)
e = ApiError(400, "bad request")
print(e.code, str(e))

def redact_headers(h):
    out = dict(h)
    if "Authorization" in out:
        out["Authorization"] = "Bearer ***"
    return out
print(redact_headers({"Authorization": "Bearer SECRET", "Accept": "json"}))

ALLOWED_EGRESS_FIELDS = {"city", "address_line", "country"}
def filter_egress(payload):
    return {k: v for k, v in payload.items() if k in ALLOWED_EGRESS_FIELDS}
print(filter_egress({"city": "Lima", "document_id": "SECRET"}))

import hashlib, json
body = {"lat": -12.0, "lon": -77.0}
prov = {
    "source_url": "https://example.com/geo",
    "status_code": 200,
    "body_sha12": hashlib.sha256(json.dumps(body, sort_keys=True).encode()).hexdigest()[:12],
}
print(prov)

cache = {}
def get_cached(key, fetcher):
    if key not in cache:
        cache[key] = fetcher()
    return cache[key]
print(get_cached("Lima", lambda: {"lat": -12.04}))
print(get_cached("Lima", lambda: {"lat": 0}))

def timeout_policy(seconds):
    if seconds <= 0:
        raise ValueError("timeout")
    return seconds
print(timeout_policy(5))

REQUIRED = {"lat", "lon", "provider"}
PRECALC = {"Lima": {"lat": -12.0464, "lon": -77.0428, "provider": "precalc"}}
def contract_ok(d):
    return not (REQUIRED - set(d.keys()))
def geocode(city, fail_online=False):
    if fail_online:
        return {**PRECALC[city], "mode": "offline_fallback"}
    return {"lat": -12.0464, "lon": -77.0428, "provider": "online", "mode": "online"}
print(contract_ok(geocode("Lima")))
print(geocode("Lima", fail_online=True)["mode"])

def validate_geo(d):
    for k in ("lat", "lon"):
        if k not in d:
            return False
        if not isinstance(d[k], (int, float)):
            return False
    return True
print(validate_geo({"lat": 1.0, "lon": 2.0}), validate_geo({"lat": "x"}))

def offline_table():
    return {"Lima": (-12.0464, -77.0428), "Arequipa": (-16.4090, -71.5375)}
print(sorted(offline_table()))

def unit_of_work(ops):
    done = []
    try:
        for op in ops:
            done.append(op())
        return done
    except Exception:
        return "rollback"
print(unit_of_work([lambda: 1, lambda: 2]))

class MockGeocoder:
    DB = {"Lima": (-12.0464, -77.0428), "Arequipa": (-16.4090, -71.5375)}
    def geocode(self, city):
        if city not in self.DB:
            return None
        lat, lon = self.DB[city]
        return {"city": city, "lat": lat, "lon": lon, "provider": "authorized_mock"}
g = MockGeocoder()
print(g.geocode("Lima")["provider"], g.geocode("Iquitos"))

def assert_mock_only(provider):
    assert provider in {"authorized_mock", "precalc", "offline_fallback"}
    return True
print(assert_mock_only("authorized_mock"))

def geo_signal(km, threshold=2.0):
    return {"geo_distance_km": km, "close": km <= threshold, "verdict": None}
print(geo_signal(1.2))

def as_relationship_signal(km):
    return {
        "type": "geo_distance",
        "km": km,
        "relationship_signal_score": max(0.0, min(1.0, 1.0 - km / 10.0)),
        "verdict": None,
    }
print(as_relationship_signal(1.2)["verdict"])
